        return hex.chunked(2).map { it.toInt(16).toByte() }.toByteArray()
    }

    fun generateFrameAsNeeded(): ByteArray {
        Log.i(TAG, "[+] Using captured frame replay (${frameIndex % CAPTURED_FRAMES.size}/${CAPTURED_FRAMES.size})")
        return getNextFrame()
    }
